const CATS = [...new Set(CARDS.map((c) => c.cat))];
const COVER_CATS = CATS.filter((c) => !["몸풀기", "갈무리", "마지막"].includes(c));
const STORE_KEY = "banjeol-2026-h1-answers";
const sentences = (t) =>
  (t.match(/[^.?!]+[.?!]+["')\]]*\s*|[^.?!]+$/g) || [t]).map((s) => s.trim()).filter(Boolean);
const fmtDate = (ts) => {
  if (!ts) return "";
  const d = new Date(ts);
  return `${d.getMonth() + 1}월 ${d.getDate()}일 ${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};

/* 저장 안전망: 아티팩트 저장소 → 브라우저 저장소 → 임시 메모리 순으로 시도 */
const store = {
  mode: null, // 'cloud' | 'local' | 'memory'
  mem: null,
  async load(key) {
    try {
      const r = await window.storage.get(key);
      this.mode = "cloud";
      return r?.value ?? null;
    } catch (e) { /* 키 없음 또는 API 없음 */ }
    if (this.mode !== "cloud") {
      try {
        const v = window.localStorage.getItem(key);
        this.mode = "local";
        return v;
      } catch (e) { /* localStorage 불가 */ }
      this.mode = "memory";
    }
    return this.mem;
  },
  async save(key, value) {
    try {
      await window.storage.set(key, value);
      this.mode = "cloud";
      return "cloud";
    } catch (e) { /* 다음 단계로 */ }
    try {
      window.localStorage.setItem(key, value);
      this.mode = "local";
      return "local";
    } catch (e) { /* 다음 단계로 */ }
    this.mem = value;
    this.mode = "memory";
    return "memory";
  },
};

